css:
@page {
    size: A4;
    margin: 1cm;
}

.page-break{
page-break-before: always;
}

@media print {

button,
.no-print,
.interactive {
display:none;
}

}

html:
{{letter_head}}
{{ get_shop_name() }}
<h3>{{ _("Customer Details") }}</h3>
Job Card Recipt
<p>
{{ _("Customer") }}: {{ doc.customer_name }} <br>
{{ _("Phone") }}: {{ doc.customer_phone }}
</p>

<h3>{{ _("Device Details") }}</h3>

<p>
{{"Device Brand"}}: {{ doc.device_brand }}<br>
{{"Device Model"}}: {{ doc.device_model }} <br>
{{"Device Type"}}: {{ doc.device_type }}
</p>

<table>
<tr>
<th>{{ _("Part") }}</th>
<th>{{ _("Quantity") }}</th>
<th>{{"Unit Price"}}</th>
<th>{{ _("Total Price") }}</th>
</tr>

{% for part in doc.parts_used%}

<tr>
<td>{{ part.part }}</td>
<td>{{ part.quantity }}</td>
<td>{{ part.unit_price }}</td>
<td>{{part.total_price}}</td>
</tr>

{% endfor %}

</table>

<h2 style="font-size:26px;font-weight:bold;">
{{ _("Final Amount") }} :
{{ frappe.utils.fmt_money(doc.final_amount) }}
</h2>
{% if doc.priority == "Urgent" %}

<div class="urgent">
URGENT
</div>

{% endif %}
<p><b>{{ doc.print_summary }}</b></p>
<style>

@page {
    size: A4;
    margin: 1cm;
}

</style>

{% if doc.parts_used|length > 10 %}

<div class="page-break"></div>

{% endif %}

<img width="120"
src="data:image/png;base64,{{ generate_qr(doc.get_url()) }}">

<footer>
    {{footer}}
</footer>
